//! Fleet admission budget — the AntColony FRF gate.
//!
//! Mirrors `Gnosis.AntColonyCollectiveIntelligence` (open-source/gnosis-math).
//! The subagent fleet is read as an ant colony's FRF profile:
//!
//!   fork = breeders + reproductiveVoid     (spawn capacity)
//!   race = reproductiveVoid + scouts        (competing workers)
//!   fold = breeders                         (persistent stations)
//!   vent = ventBurden                       (revocations / kills)
//!
//! Two structural guarantees come straight from the Lean module and become
//! the runtime guardrails on `create`/`delete`:
//!
//!   * `stabilityWeight = budget − min(vent, budget) + 1` is *always ≥ 1*
//!     (`stability_weight_positive`): a fleet never collapses to nothing —
//!     the trailing `+1` is the "one queen survives the budding" floor.
//!   * the two-queen budding floor (`budding_two_queen_floor`,
//!     `budding_survives_one_queen_loss`): reaping must never drop the
//!     persistent-breeder count below `min_breeders`, so the colony survives
//!     the loss of any single queen.
//!
//! Population is gated against a manifold ceiling (Gnosis tower ceilings,
//! cf. `cost_algebra::tower_ceilings`), the present-pillar anchor: the live
//! fleet may not exceed the ceiling.

use serde::{Deserialize, Serialize};

/// Canonical Gnosis tower ceilings (mirrors `cost_algebra::tower_ceilings`
/// in distributed-inference). The default population ceiling is DECAGON (10),
/// one slot per bit of the 10-bit aeon frame the swarm talks over.
pub mod tower_ceilings {
    pub const TRITON: u32 = 3;
    pub const HEXON: u32 = 6;
    pub const ENNEON: u32 = 9;
    pub const DECAGON: u32 = 10;
    pub const DODECAGON: u32 = 12;
    pub const TRIHEXON: u32 = 18;
}

/// A subagent's caste in colony terms. Breeders are persistent stations that
/// carry the fold mode purely (`breeders_are_pure_fold_mode`); scouts are
/// ephemeral workers on the race extension.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum Caste {
    Breeder,
    Scout,
}

impl Caste {
    pub fn as_str(self) -> &'static str {
        match self {
            Caste::Breeder => "breeder",
            Caste::Scout => "scout",
        }
    }
    pub fn parse(s: &str) -> Option<Caste> {
        match s {
            "breeder" => Some(Caste::Breeder),
            "scout" => Some(Caste::Scout),
            _ => None,
        }
    }
}

/// The colony's FRF profile, computed from the live fleet.
/// Mirrors `Gnosis.AntColonyCollectiveIntelligence.AntColony.toFRF`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct FleetProfile {
    pub breeders: u32,
    /// Spare spawn capacity (the reproductive void: the operator-chord that
    /// feeds both fork and race, `reproductive_void_bounds_fork_and_race`).
    pub reproductive_void: u32,
    pub scouts: u32,
    pub vent_burden: u32,
}

impl FleetProfile {
    pub fn fork(&self) -> u32 {
        self.breeders + self.reproductive_void
    }
    pub fn race(&self) -> u32 {
        self.reproductive_void + self.scouts
    }
    pub fn fold(&self) -> u32 {
        self.breeders
    }
    /// `resourceBudget = fork + race + fold`.
    pub fn resource_budget(&self) -> u32 {
        self.fork() + self.race() + self.fold()
    }
    /// The God Formula: `budget − min(vent, budget) + 1`. Always ≥ 1.
    /// Mirrors `FRFProfile.stabilityWeight` / `stability_weight_is_god_formula`.
    pub fn stability_weight(&self) -> u32 {
        let budget = self.resource_budget();
        budget - budget.min(self.vent_burden) + 1
    }
    /// Live population (breeders + scouts): what counts against the ceiling.
    pub fn population(&self) -> u32 {
        self.breeders + self.scouts
    }
}

/// The admission policy. `population_ceiling` is the present-pillar manifold
/// ceiling; `min_breeders` is the two-queen reap floor.
#[derive(Clone, Copy, Debug)]
pub struct FleetBudget {
    pub population_ceiling: u32,
    pub min_breeders: u32,
}

impl Default for FleetBudget {
    fn default() -> Self {
        Self {
            // One slot per bit of the 10-bit aeon frame.
            population_ceiling: tower_ceilings::DECAGON,
            // The colony always keeps at least one queen.
            min_breeders: 1,
        }
    }
}

/// The outcome of an admission check, carrying the post-op stability weight
/// when admitted (always ≥ 1) and a human reason when denied.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Admission {
    Admit { stability_weight: u32 },
    Deny(String),
}

impl Admission {
    pub fn is_admitted(&self) -> bool {
        matches!(self, Admission::Admit { .. })
    }
}

impl FleetBudget {
    /// Gate a `create` (a budding event). The new member is admitted only if
    /// the live population stays within the manifold ceiling. The resulting
    /// colony's stability weight is reported (theorem: always ≥ 1).
    pub fn admit_spawn(&self, current: &FleetProfile, caste: Caste) -> Admission {
        if current.population() + 1 > self.population_ceiling {
            return Admission::Deny(format!(
                "population ceiling reached: {} live (manifold ceiling {})",
                current.population(),
                self.population_ceiling
            ));
        }
        let next = match caste {
            Caste::Breeder => FleetProfile {
                breeders: current.breeders + 1,
                ..*current
            },
            Caste::Scout => FleetProfile {
                scouts: current.scouts + 1,
                ..*current
            },
        };
        Admission::Admit {
            stability_weight: next.stability_weight(),
        }
    }

    /// Gate a `delete` (reap). Reaping a breeder must not drop the persistent
    /// breeder count below `min_breeders` — the two-queen budding floor, so
    /// the colony survives the loss of a queen.
    pub fn admit_reap(&self, current: &FleetProfile, caste: Caste) -> Admission {
        if caste == Caste::Breeder && current.breeders <= self.min_breeders {
            return Admission::Deny(format!(
                "two-queen floor: cannot reap the last {} breeder(s); the colony must keep ≥ {}",
                current.breeders, self.min_breeders
            ));
        }
        // A reap vents one unit; the colony stays stable by the God Formula.
        let next = match caste {
            Caste::Breeder => FleetProfile {
                breeders: current.breeders.saturating_sub(1),
                vent_burden: current.vent_burden + 1,
                ..*current
            },
            Caste::Scout => FleetProfile {
                scouts: current.scouts.saturating_sub(1),
                vent_burden: current.vent_burden + 1,
                ..*current
            },
        };
        Admission::Admit {
            stability_weight: next.stability_weight(),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn profile(b: u32, v: u32, s: u32, vent: u32) -> FleetProfile {
        FleetProfile {
            breeders: b,
            reproductive_void: v,
            scouts: s,
            vent_burden: vent,
        }
    }

    #[test]
    fn stability_weight_always_positive() {
        // Mirrors `stability_weight_positive`: the +1 floor never collapses.
        for vent in 0..20u32 {
            let p = profile(0, 0, 0, vent);
            assert!(p.stability_weight() >= 1, "vent={vent}");
        }
    }

    #[test]
    fn stability_weight_is_god_formula() {
        let p = profile(2, 1, 3, 4);
        let budget = p.resource_budget();
        assert_eq!(p.stability_weight(), budget - budget.min(4) + 1);
    }

    #[test]
    fn spawn_admitted_below_ceiling() {
        let budget = FleetBudget {
            population_ceiling: 3,
            min_breeders: 1,
        };
        let p = profile(1, 1, 1, 0); // 2 live
        match budget.admit_spawn(&p, Caste::Scout) {
            Admission::Admit { stability_weight } => assert!(stability_weight >= 1),
            other => panic!("expected admit, got {other:?}"),
        }
    }

    #[test]
    fn spawn_denied_at_ceiling() {
        let budget = FleetBudget {
            population_ceiling: 2,
            min_breeders: 1,
        };
        let p = profile(1, 0, 1, 0); // 2 live == ceiling
        assert!(!budget.admit_spawn(&p, Caste::Scout).is_admitted());
    }

    #[test]
    fn reap_denied_for_last_breeder() {
        // Two-queen floor: a lone queen cannot be reaped.
        let budget = FleetBudget {
            population_ceiling: 10,
            min_breeders: 1,
        };
        let p = profile(1, 0, 3, 0);
        assert!(!budget.admit_reap(&p, Caste::Breeder).is_admitted());
        // ...but a scout always can.
        assert!(budget.admit_reap(&p, Caste::Scout).is_admitted());
    }

    #[test]
    fn budding_survives_one_queen_loss() {
        // Mirrors `budding_survives_one_queen_loss`: with two queens, reaping
        // one is admitted and leaves a surviving colony.
        let budget = FleetBudget {
            population_ceiling: 10,
            min_breeders: 1,
        };
        let p = profile(2, 0, 0, 0);
        assert!(budget.admit_reap(&p, Caste::Breeder).is_admitted());
    }
}
